local project_path = rawget(_G, "__LOVE2D_PROJECT_PATH") or "."
local port_file = rawget(_G, "__LOVE2D_BRIDGE_PORT_FILE") or (project_path .. "/.love2d-hot-port")
local startup_error_file = rawget(_G, "__LOVE2D_STARTUP_ERROR_FILE")
